"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

// ── Types ─────────────────────────────────────────────────────────────────────

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  state: "active" | "completed" | "pending"
}

// ── Contexts ──────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

// ── Hooks ─────────────────────────────────────────────────────────────────────

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

// ── CVA ───────────────────────────────────────────────────────────────────────

const stepperTriggerVariants = cva(
  "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      state: {
        active: "border-primary bg-primary text-primary-foreground",
        completed: "border-primary bg-primary text-primary-foreground",
        pending:
          "border-muted-foreground/40 bg-background text-muted-foreground",
      },
    },
    defaultVariants: {
      state: "pending",
    },
  }
)

// ── Components ────────────────────────────────────────────────────────────────

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep, orientation } = useStepper()

  const state: "active" | "completed" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-center gap-2"
            : "flex-col items-start gap-1",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      className={cn(stepperTriggerVariants({ state }), className)}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "flex-1 rounded-full bg-muted transition-colors",
        state === "completed" && "bg-primary",
        orientation === "horizontal" ? "h-0.5 min-w-4" : "w-0.5 min-h-4",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  stepperTriggerVariants,
}

"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Set up your account credentials.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Tell us a bit about yourself.",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set — welcome aboard!",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="w-full max-w-xl space-y-6">
      <Stepper activeStep={activeStep} className="w-full">
        {steps.map(({ step, title }, index) => (
          <StepperItem key={step} step={step} className="flex-1">
            <StepperTrigger onClick={() => setActiveStep(step)} />
            <StepperTitle>{title}</StepperTitle>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>

      {steps.map(({ step, description }) => (
        <StepperContent key={step} step={step}>
          <p className="text-sm text-muted-foreground">{description}</p>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          disabled={activeStep === 1}
          onClick={() => setActiveStep((prev) => Math.max(1, prev - 1))}
        >
          Previous
        </Button>
        <Button
          disabled={activeStep === steps.length}
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length, prev + 1))
          }
        >
          Next
        </Button>
      </div>
    </div>
  )
}
